create extension if not exists "pgcrypto";create table if not exists public.projects(id uuid primary key default gen_random_uuid(),title text not null,description text not null,price bigint not null default 0,category text,demo_url text,image_url text,published boolean not null default true,created_at timestamptz not null default now());alter table public.projects enable row level security;create policy "Public can view published projects" on public.projects for select using(published=true or auth.role()='authenticated');create policy "Authenticated users can insert projects" on public.projects for insert to authenticated with check(true);create policy "Authenticated users can update projects" on public.projects for update to authenticated using(true) with check(true);create policy "Authenticated users can delete projects" on public.projects for delete to authenticated using(true);